SELECT COUNT(*) AS total_servidores FROM servidor s WHERE LOWER(s.categoria) = LOWER('docente') AND LOWER(s.contrato) = LOWER('efetivos') AND LOWER(s.area_ingresso) = LOWER('geografia') AND s.saiu_do_ifg = FALSE AND LOWER(s.sigla_campus) = LOWER('gyn') AND EXISTS (SELECT 1 FROM calc_hora_aula_media c WHERE c.siape = s.pk_siape AND c.ano = 2024 AND c.semestre = 1 AND LOWER(c.sigla_campus) = LOWER('gyn') AND LOWER(c.area_ingresso) = LOWER('geografia'))